import { describe, expect, it } from "vitest";
import { parseSessionLogConsentArgs } from "./sessionLogConsent.js";
describe("parseSessionLogConsentArgs", () => {
    it("defaults to get with no args", () => {
        expect(parseSessionLogConsentArgs([])).toEqual({ kind: "get" });
    });
    it('treats explicit "get" as a read', () => {
        expect(parseSessionLogConsentArgs(["get"])).toEqual({ kind: "get" });
    });
    it('parses "set true"', () => {
        expect(parseSessionLogConsentArgs(["set", "true"])).toEqual({
            kind: "set",
            value: true,
        });
    });
    it('parses "set false"', () => {
        expect(parseSessionLogConsentArgs(["set", "false"])).toEqual({
            kind: "set",
            value: false,
        });
    });
    it("throws when set has a non-boolean value", () => {
        expect(() => parseSessionLogConsentArgs(["set", "yes"])).toThrow(/set true.*set false/);
    });
    it("throws when set has no value", () => {
        expect(() => parseSessionLogConsentArgs(["set"])).toThrow(/set true.*set false/);
    });
    it("throws on an unknown verb", () => {
        expect(() => parseSessionLogConsentArgs(["toggle"])).toThrow(/Unknown session-log-consent command/);
    });
});
